('PT', 'specjalistyczne'::question_type, 2, 'Z jakiego powodu motorniczy powinien zwolnić przejeżdżając przez miejsce z obniżoną siecią trakcyjną np. pod wiaduktem?', '{"A": "Ponieważ szybki przejazd przez takie miejsce powoduje echo, które może przeszkadzać mieszkańcom okolicznych domów.", "B": "Ponieważ szybki przejazd przez takie miejsce może uszkodzić odbierak prądu oraz trakcję.", "C": "Ponieważ będzie utrudnione hamowanie pojazdu."}'::jsonb, 'B'),
('PT', 'podstawowe'::question_type, 1, 'Czy przed ręcznym przełożeniem zwrotnicy motorniczy powinien "zaparkować" tramwaj?', NULL, 'TAK'),
('PT', 'podstawowe'::question_type, 1, 'Czy w czasie postoju na pętli masz prawo opuścić tramwaj bez zabezpieczenia go?', NULL, 'NIE'),
('PT', 'podstawowe'::question_type, 3, 'Czy motorniczy ma prawo prowadzić tramwaj w stanie po użyciu alkoholu (np. po wypiciu jednego piwa), jeśli czuje się dobrze?', NULL, 'NIE'),
('PT', 'podstawowe'::question_type, 3, 'Czy motorniczy, uwzględniając wszystkie formy zatrudnienia, może odpoczywać krócej niż 11 godzin na dobę?', NULL, 'NIE'),
('PT', 'podstawowe'::question_type, 3, 'Czy podczas kierowania tramwajem masz prawo rozmawiać przez telefon komórkowy, jeżeli nie trzymasz słuchawki i mikrofonu w ręku?', NULL, 'TAK'),
('PT', 'podstawowe'::question_type, 3, 'Czy motorniczemu wykonującemu przewozy pasażerskie, przysługuje prawo do co najmniej 35 godzin nieprzerwanego odpoczynku w tygodniu?', NULL, 'TAK'),
('PT', 'specjalistyczne'::question_type, 1, 'Która z wymienionych przyczyn może powodować przerwy w dopływie prądu wysokiego napięcia bezpośrednio do wagonu?', '{"A": "Uszkodzenie baterii.", "B": "Uszkodzenie dzwonka zewnętrznego.", "C": "Wyszczerbiona wkładka grafitowa pantografu."}'::jsonb, 'C'),
('PT', 'specjalistyczne'::question_type, 1, 'Jaki skutek może wywołać wyszczerbienie grafitowej wkładki pantografu?', '{"A": "Zwiększenie poboru prądu z sieci trakcyjnej.", "B": "Nadmierne kołysanie się, a nawet zerwanie sieci trakcyjnej.", "C": "Zawsze niezakłócone działanie pantografu."}'::jsonb, 'B'),
('PT', 'specjalistyczne'::question_type, 1, 'Kiedy używa się hamulca mechanicznego (nazywanego też postojowym)?', '{"A": "We wszystkich fazach hamowania.", "B": "Tylko w końcowej fazie hamowania i podczas postoju.", "C": "Tylko podczas postoju."}'::jsonb, 'B'),
('PT', 'specjalistyczne'::question_type, 1, 'Który z wymienionych czynników powoduje działanie hamulca postojowego?', '{"A": "Cewka elektromagnetyczna.", "B": "Docisk sprężyny.", "C": "Układ dźwigni."}'::jsonb, 'B'),
('PT', 'specjalistyczne'::question_type, 1, 'Od czego zależy sprawność hamulców elektrodynamicznych?', '{"A": "Od sprawności silników trakcyjnych.", "B": "Od sprawności baterii tramwaju.", "C": "Hamulce elektordynamiczne są niezależne od systemów tramwaju."}'::jsonb, 'A'),
('PT', 'specjalistyczne'::question_type, 1, 'Co należy zrobić aby zwolnić (zluzować) hamulce postojowe do holowania uszkodzonego tramwaju?', '{"A": "Wyłączyć wagon, po jego wyłączeniu hamulce są automatycznie zluzowane.", "B": "Odpiąć mechanicznie lub elektrycznie luzowniki.", "C": "Ustawić nawrotnik w położenie neutralne."}'::jsonb, 'B'),
('PT', 'podstawowe'::question_type, 2, 'Czy w każdym przypadku masz obowiązek zachować odległość co najmniej 1 metra od omijanego pojazdu, uczestnika ruchu lub przeszkody?', NULL, 'NIE'),
('PT', 'podstawowe'::question_type, 2, 'Czy motorniczy, który nie ma możliwości obserwacji drogi za tramwajem, może cofać, nie zapewniając sobie pomocy innej osoby?', NULL, 'NIE'),
('PT', 'podstawowe'::question_type, 2, 'Czy motorniczy, który źle przełożył zwrotnicę i zauważył to ok. 1 m za nią, ma prawo wycofać tramwaj nie sprawdzając, czy nie spowoduje tym zagrożenia?', NULL, 'NIE'),
('PT', 'podstawowe'::question_type, 2, 'Czy masz obowiązek zachować szczególną ostrożność, gdy omijasz pojazd przewożący zorganizowaną grupę dzieci do 18 lat, które z niego wysiadają?', NULL, 'TAK'),
('PT', 'specjalistyczne'::question_type, 1, 'Jakiego rodzaju hamulcem jest hamulec postojowy?', '{"A": "Aktywny - działa tylko po załączeniu tramwaju i naciśnięciu pedału hamulca.", "B": "Pasywny - działa nawet po wyłączeniu tramwaju.", "C": "Pasywny - działa tylko po opuszczeniu pantografu w wagonie."}'::jsonb, 'B'),
('PT', 'specjalistyczne'::question_type, 1, 'Jaki skutek wywoła zatrzymanie wagonu w miejscu styku pantografu z izolatorem?', '{"A": "Zanik rozruchu wagonu oraz pracy przetwornicy.", "B": "Zadziałanie hamulców szynowych.", "C": "Uszkodzenie grafitowej wkładki pantografu."}'::jsonb, 'A'),
('PT', 'specjalistyczne'::question_type, 3, 'W jakich sytuacjach motorniczy może wpuścić lub wypuścić pasażera, któremu się bardzo śpieszy?', '{"A": "W czasie oczekiwania na zmianę światła.", "B": "Tylko znajdując się na przystanku.", "C": "Poza przystankiem, na wyraźną prośbę pasażera."}'::jsonb, 'B'),
('PT', 'specjalistyczne'::question_type, 1, 'Które, z tych oznaczeń tramwaju, oprócz oznakowania liniowego, jest wymagane?', '{"A": "Numer taborowy.", "B": "Tablica rejestracyjna, jak samochody.", "C": "Numer taborowy, logo i nazwa miasta, w którym porusza się tramwaj."}'::jsonb, 'A'),
('PT', 'specjalistyczne'::question_type, 3, 'W jakich miejscach motorniczy może wpuszczać lub wypuszczać pasażerów?', '{"A": "W każdym miejscu, w tym także na przystankach.", "B": "Na przystankach.", "C": "Wyłącznie na pętlach."}'::jsonb, 'B'),
('PT', 'specjalistyczne'::question_type, 1, 'Czy kierując tramwajem, masz obowiązek posiadać przy sobie pozwolenie na kierowanie tym pojazdem?', '{"A": "Tak, zawsze.", "B": "Nie, ponieważ nie jest wymagane w komunikacji miejskiej.", "C": "Nie, o ile posiada odpowiedni dokument wydany przez pracodawcę."}'::jsonb, 'A'),
('PT', 'specjalistyczne'::question_type, 1, 'Jak należy postąpić w przypadku wymiany przepalonego bezpiecznika topikowego - wysokiego napięcia?', '{"A": "Jedynie wyłączyć przetwornicę.", "B": "Opuścić pantograf (odbierak).", "C": "Jedynie założyć rękawice."}'::jsonb, 'B'),
('PT', 'specjalistyczne'::question_type, 3, 'Co powinien zrobić motorniczy przed rozpoczęciem jazdy, bezpośrednio po zamknięciu drzwi?', '{"A": "Uważnie obserwować otoczenie dookoła i podać sygnał odjazdu dzwonkiem.", "B": "Wystarczy, że poda sygnał odjazdu dzwonkiem.", "C": "Wyłącznie sprawdzić sygnalizację zamknięcia drzwi."}'::jsonb, 'A'),
('PT', 'specjalistyczne'::question_type, 3, 'Jaka pozycja motorniczego jest prawidłowa podczas ręcznego przestawiania zwrotnicy?', '{"A": "Pozycja motorniczego nie ma znaczenia.", "B": "Tyłem do tramwaju.", "C": "Przodem do tramwaju."}'::jsonb, 'C'),
('PT', 'specjalistyczne'::question_type, 3, 'W jakim miejscu motorniczy może wypuścić pasażerów z powodu długotrwałych utrudnień w ruchu drogowym?', '{"A": "W dowolnie wybranym miejscu.", "B": "Jedynie na przystanku, bez względu na okoliczności.", "C": "W miejscu, w którym nie ma zagrożenia dla pasażerów i dla ruchu drogowego."}'::jsonb, 'C'),
('PT', 'specjalistyczne'::question_type, 3, 'Co powinien zrobić motorniczy, aby bezpiecznie dokonać elektrycznego połączenia wagonów?', '{"A": "Wystarczy, że opuści pantografy.", "B": "Wystarczy, że odłączy akumulatory.", "C": "Opuścić pantografy i odłączyć akumulatory."}'::jsonb, 'C'),
('PT', 'specjalistyczne'::question_type, 3, 'Jak powinien zachować się motorniczy przed wyjściem z kabiny na jezdnię, poza przystankiem, w celu ręcznego ustawienia zwrotnicy?', '{"A": "Wyłączyć przetwornicę.", "B": "Zaparkować tramwaj i upewnić się czy może bezpiecznie opuścić kabinę.", "C": "Wyłączyć wszystkie światła tramwaju i ustawić nawrotnik w położenie neutralne."}'::jsonb, 'B'),
('PT', 'specjalistyczne'::question_type, 3, 'Co może być przyczyną przerwania jazdy w czasie rozruchu, jeżeli dzwoni dzwonek wewnętrzny i brak jest sygnalizacji zamkniętych drzwi?', '{"A": "Otwarcie okna, jeżeli wnętrze jest klimatyzowane.", "B": "Awaryjne otwarcie drzwi przez pasażera.", "C": "Przepalenie się bezpiecznika przetwornicy."}'::jsonb, 'B'),
('PT', 'specjalistyczne'::question_type, 3, 'Jak powinieneś zachować się, gdy kierujesz tramwajem w czasie burzy z wyładowaniami atmosferycznymi i obawiasz się uderzenia pioruna?', '{"A": "Zatrzymać tramwaj, opuścić pantografy i wypuścić pasażerów.", "B": "Kontynuować jazdę, wnętrze tramwaju jest bezpieczne.", "C": "Zatrzymać tramwaj, opuścić pantografy i nie wypuszczać pasażerów."}'::jsonb, 'B'),
('PT', 'specjalistyczne'::question_type, 2, 'Jak powinien zachować się motorniczy przejeżdżając przez miejsca z obniżoną siecią trakcyjną np. pod wiaduktem?', '{"A": "Zmniejszyć prędkość na całym odcinku obniżenia.", "B": "Zwiększyć prędkość na całym odcinku obniżenia.", "C": "Zawsze utrzymać stałą prędkość."}'::jsonb, 'A'),
('PT', 'specjalistyczne'::question_type, 2, 'W jaki sposób powinien jechać motorniczy zbliżając się do skrzyżowania?', '{"A": "Na wybiegu lub hamując.", "B": "Na rozruchu, przyspieszając.", "C": "Z maksymalną dopuszczalną prędkością."}'::jsonb, 'A'),
('PT', 'specjalistyczne'::question_type, 2, 'W jakiej sytuacji motorniczy może bezpiecznie przejechać przez zwrotnicę?', '{"A": "Gdy sygnalizator zwrotnicy wskazuje, że została przestawiona.", "B": "Bez zwracania na nią uwagi, jeśli ma opóźnienie względem rozkładu jazdy.", "C": "Gdy iglice zwrotnicy prawidłowo przylegają."}'::jsonb, 'C'),
('PT', 'specjalistyczne'::question_type, 2, 'Jakiego zachowania wymaga od motorniczego przejazd tramwajem przez zwrotnice i krzyżownice?', '{"A": "Zwiększenia prędkości.", "B": "Zmniejszenia prędkości.", "C": "Bez zmiany prędkości."}'::jsonb, 'B'),
('PT', 'specjalistyczne'::question_type, 2, 'Jaką zasadą techniki jazdy powinien kierować się motorniczy wjeżdżając w ostry łuk toru?', '{"A": "Zachowania dotychczasowej prędkości.", "B": "Zwiększania prędkości.", "C": "Zmniejszania prędkości."}'::jsonb, 'C'),
('PT', 'specjalistyczne'::question_type, 2, 'Jaki wpływ na obsługę urządzeń sterujących ma ustawienie fotela motorniczego?', '{"A": "Nie ma żadnego wpływu.", "B": "Ma niewielki wpływ.", "C": "Ma kluczowy wpływ."}'::jsonb, 'C'),
('PT', 'specjalistyczne'::question_type, 2, 'Jeśli wystąpi poślizg kół tramwaju w czasie rozruchu, należy go przerwać, a następnie:', '{"A": "ponowić rozruch łagodniej.", "B": "ponowić rozruch bardziej energicznie.", "C": "koniecznie zatrzymać tramwaj."}'::jsonb, 'A'),
('PT', 'specjalistyczne'::question_type, 2, 'Co powinien zrobić motorniczy podczas nagłego pojawienia się pojazdu na torach bezpośrednio przed tramwajem?', '{"A": "Łagodnie hamować aby nie powodować zagrożenia dla pasażerów.", "B": "Zdecydowanie hamować starając się uniknąć zderzenia.", "C": "Zrezygnować z hamowania."}'::jsonb, 'B'),
('PT', 'specjalistyczne'::question_type, 2, 'Jak należy prowadzić rozruch tramwaju?', '{"A": "W sposób nie powodujący poślizgu kół.", "B": "W sposób powodujący znaczne przyspieszenie.", "C": "W sposób nie powodujący dużego obciążenia baterii akumulatorów."}'::jsonb, 'A'),
('PT', 'specjalistyczne'::question_type, 1, 'Które hamulce są wykorzystane do łagodnego zatrzymania tramwaju na przystanku?', '{"A": "Wszystkie rodzaje hamulców.", "B": "Hamulec elektrodynamiczny i w końcowej fazie hamulec postojowy.", "C": "Hamulec szynowy i hamulec elektrodynamiczny."}'::jsonb, 'B'),
('PT', 'specjalistyczne'::question_type, 2, 'Jaki skutek może spowodować łuk elektryczny powstający przy przejeżdżaniu przez izolator z załączoną jazdą?', '{"A": "Spadek napięcia baterii.", "B": "Uszkodzenie pantografu (odbieraka).", "C": "Uszkodzenie odgromnika."}'::jsonb, 'B'),
('PT', 'specjalistyczne'::question_type, 2, 'Kiedy motorniczy ma obowiązek dostosowania prędkości do warunków na drodze?', '{"A": "Zawsze.", "B": "Nie ma takiego obowiązku.", "C": "Tylko w okolicach przejść dla pieszych."}'::jsonb, 'A'),
('PT', 'specjalistyczne'::question_type, 3, 'Co motorniczy powinien zrobić, gdy po wejściu pasażerów nie chcą się zamknąć drzwi i konieczna jest ich fachowa naprawa?', '{"A": "Poprosić wszystkich pasażerów o wyjście i pustym tramwajem wrócić do zajezdni.", "B": "Rozpocząć jazdę z otwartymi drzwiami, uprzedzając pasażerów o możliwych niedogodnościach.", "C": "Wyłączyć blokadę jazdy i kontynuować jazdę z pasażerami."}'::jsonb, 'A'),
('PT', 'specjalistyczne'::question_type, 1, 'Co powinien zrobić motorniczy dojeżdżając do zanieczyszczonej zwrotnicy?', '{"A": "Jechać dalej nie zwracając uwagi na stan zanieczyszczenia.", "B": "Zatrzymać się i oczyścić zwrotnicę przed najechaniem na nią.", "C": "Wezwać służby oczyszczania miasta."}'::jsonb, 'B'),
('PT', 'specjalistyczne'::question_type, 2, 'Co powinien zrobić motorniczy po ruszeniu tramwajem?', '{"A": "Wielokrotnie załączać jazdę, aż do osiągnięcia pożądanej prędkości.", "B": "Rozpędzić tramwaj do pożądanej prędkości i jak najdłużej jechać na wybiegu.", "C": "Puścić czuwak."}'::jsonb, 'B'),
('PT', 'specjalistyczne'::question_type, 2, 'W jaki sposób motorniczy powinien przejeżdżać pod izolatorami sekcyjnymi umieszczonymi na sieci trakcyjnej?', '{"A": "Zawsze na rozruchu, gdyż inaczej tramwaj zatrzyma się pod izolatorem z powodu braku prądu.", "B": "Na wybiegu lub na hamowaniu.", "C": "Zawsze na hamowaniu, gdyż wtedy tramwaj poprzez izolator oddaje prąd do sieci trakcyjnej."}'::jsonb, 'B'),
('PT', 'specjalistyczne'::question_type, 2, 'Co spowoduje wciśnięcie czuwaka podczas postoju tramwaju?', '{"A": "Opadnięcie hamulców szynowych.", "B": "Umożliwienie rozruchu tramwaju.", "C": "Włączenie oświetlenia tramwaju."}'::jsonb, 'B'),
('PT', 'specjalistyczne'::question_type, 3, 'Jaka jest maksymalna dopuszczalna prędkość tramwaju na obszarze zabudowanym w godzinach 5:00 - 23:00 (jeżeli znaki drogowe nie wskazują inaczej)?', '{"A": "60 km/h", "B": "50 km/h", "C": "55 km/h"}'::jsonb, 'B'),
('PT', 'specjalistyczne'::question_type, 3, 'Z czym powinien liczyć się motorniczy holując uszkodzony tramwaj?', '{"A": "Ze zwiększonym prawdopodobieństwem wykolejenia tramwaju na ostrym łuku.", "B": "Z wydłużeniem drogi hamowania.", "C": "Ze skróceniem drogi hamowania."}'::jsonb, 'B'),
('PT', 'specjalistyczne'::question_type, 3, 'Czy zmniejszenie prędkości tramwaju podczas przejeżdżania przez zwrotnicę jest konieczne?', '{"A": "Tak, jest konieczne tylko na zwrotnicach eksploatowanych jednostronnie, oznakowanych znakiem BT-4 \"Z-Stop\".", "B": "Tak, jest obowiązkowe.", "C": "Nie, nie jest obowiązkowe, gdy mogłoby to spowodować opóźnienie zjazdu ze skrzyżowania."}'::jsonb, 'B'),
('PT', 'specjalistyczne'::question_type, 2, 'Jaki skutek wywoła użycie piasecznic podczas rozruchu na śliskich szynach?', '{"A": "Ułatwi rozruch - zmniejszy poślizg kół.", "B": "Utrudni rozruch.", "C": "Nie wpłynie na rozruch."}'::jsonb, 'A'),
('PT', 'specjalistyczne'::question_type, 2, 'W którego rodzaju gaśnicę powinien być wyposażony tramwaj?', '{"A": "Pianową.", "B": "Wodną.", "C": "Śniegową lub proszkową."}'::jsonb, 'C'),
('PT', 'specjalistyczne'::question_type, 2, 'Czy jazda tramwajem bez osłony sprzęgów międzywagonowych od strony drzwi pasażerskich jest dozwolona?', '{"A": "Jest zabroniona.", "B": "Jest dozwolona w każdym przypadku.", "C": "Jest dozwolona, o ile na sprzęgach znajduje się oznaczenie informujące o zakazie wchodzenia między wagony."}'::jsonb, 'C'),
('PT', 'specjalistyczne'::question_type, 2, 'W której sytuacji powinieneś używać świateł awaryjnych, jeżeli tramwaj jest w nie wyposażony?', '{"A": "Do podziękowania za udzielenie pierwszeństwa.", "B": "W czasie każdego postoju na przystanku zlokalizowanym na jezdni (nie wydzielonym).", "C": "Do sygnalizowania obecności tramwaju unieruchomionego z powodu uszkodzenia."}'::jsonb, 'C'),
('PT', 'specjalistyczne'::question_type, 2, 'W którym przypadku masz prawo wyjechać z zajezdni tramwajem z uszkodzonym zewnętrznym dzwonkiem ostrzegawczym?', '{"A": "Jeżeli będzie jeździć tylko w ciagu dnia.", "B": "W żadnym wypadku.", "C": "Jeśli usterka odnotowana jest w dokumentach tramwaju poświadczonych przez obsługę techniczną."}'::jsonb, 'B'),
('PT', 'specjalistyczne'::question_type, 2, 'Które hamulce pełnią w tramwaju funkcję awaryjnych?', '{"A": "Hamulce elektrodynamiczne.", "B": "Hamulce szczękowe.", "C": "Hamulce szynowe."}'::jsonb, 'C'),
('PT', 'specjalistyczne'::question_type, 2, 'Do czego służy obwód blokady jazdy ("zielona linia")?', '{"A": "Nie zezwala na wjazd tramwaju na tor zajęty przez tramwaj jadący z przeciwka.", "B": "Uniemożliwia jazdę tramwaju z otwartymi (niedomkniętymi) drzwiami.", "C": "Zezwala pasażerom na otwarcie drzwi przed zatrzymaniem tramwaju."}'::jsonb, 'B'),
('PT', 'specjalistyczne'::question_type, 2, 'Jaki skutek wywoła użycie piasecznic podczas hamowania na śliskich szynach?', '{"A": "Wydłuży drogę hamowania.", "B": "Skróci drogę hamowania - zmniejszy poślizg kół.", "C": "Nie wpłynie na drogę hamowania."}'::jsonb, 'B'),
('PT', 'specjalistyczne'::question_type, 3, 'W jaki sposób motorniczy może regulować siłę hamowania hamulców szynowych?', '{"A": "Tylko w ograniczonym zakresie.", "B": "W każdym zakresie.", "C": "Nie ma wpływu na regulowanie siły hamowania tych hamulców."}'::jsonb, 'C'),
('PT', 'specjalistyczne'::question_type, 3, 'Jaki powinien być odstęp od poprzedzającego tramwaju podczas jazdy?', '{"A": "Wynosić minimum 10m.", "B": "Wynosić tyle, aby możliwe było bezkolizyjne zatrzymanie pojazdu.", "C": "Jest regulowany wewnętrznymi przepisami przedsiębiorstwa."}'::jsonb, 'B'),
('PT', 'specjalistyczne'::question_type, 3, 'Które z wymienionych hamulców zostaną uruchomione, jeżeli puścisz czuwak podczas jazdy?', '{"A": "Wyłącznie hamulce szynowe.", "B": "Włącznie hamulce szczękowe.", "C": "Hamowanie awaryjne (hamulce: szynowy, szczękowy i minimalnie elektrodynamiczny)."}'::jsonb, 'C'),
('PT', 'specjalistyczne'::question_type, 3, 'Jak należy się zachować wjeżdżając na przystanek?', '{"A": "Hamować szybko i gwałtownie.", "B": "Hamować płynnie i zdecydowanie.", "C": "Hamować wykorzystując jednocześnie wszystkie 3 rodzaje hamulców."}'::jsonb, 'B'),
('PT', 'specjalistyczne'::question_type, 3, 'W jaki sposób należy hamować po wyprowadzeniu tramwaju z poślizgu?', '{"A": "Z mniejszą siłą, tak aby nie dopuścić do kolejnego zablokowania kół.", "B": "Zwalniając czuwak.", "C": "Za pomocą przeciwprądu, po uprzednim przestawieniu nawrotnika jazdy na jazdę do tyłu."}'::jsonb, 'A'),
('PT', 'specjalistyczne'::question_type, 3, 'Co powinieneś założyć ustalając odstęp od poprzedzającego tramwaju?', '{"A": "że kierujący nim może gwałtownie zahamować.", "B": "że kierujący nim nie będzie gwałtownie hamował, ponieważ wiezie pasażerów.", "C": "że kierujący nim nie będzie gwałtownie hamował, ponieważ widzi w lusterku tramwaj jadący za nim."}'::jsonb, 'A'),
('PT', 'specjalistyczne'::question_type, 3, 'Od czego może zależeć bezpieczny odstęp od poprzedzającego tramwaju?', '{"A": "Od czasu przejazdu zawartego w rozkładzie jazdy.", "B": "Od aktualnych warunków atmosferycznych.", "C": "Od liczby przystanków na danej trasie."}'::jsonb, 'B'),
('PT', 'specjalistyczne'::question_type, 3, 'Do czego powinna być dostosowana w szczególności prędkość tramwaju, od której zależy możliwość bezpiecznego zatrzymania się?', '{"A": "Od stanu torowiska i widoczności drogi.", "B": "Od mocy i liczby silników tramwaju.", "C": "Od liczby równoległych torów."}'::jsonb, 'A'),
('PT', 'specjalistyczne'::question_type, 3, 'Jak powinieneś zachować się, gdy kierując tramwajem, zbliżasz się do kałuży znajdującej się na torowisku?', '{"A": "Przejechać z jak największą prędkością.", "B": "Przejechać z jak najmniejszą prędkością.", "C": "Zatrzymać tramwaj przed każdą kałużą."}'::jsonb, 'B'),
('PT', 'specjalistyczne'::question_type, 3, 'Jaki skutek wywołuje zalegająca na torach substancja, która powstała z wilgotnych liści?', '{"A": "Zmniejsza możliwość wystąpienia poślizgu.", "B": "Nie ma żadnego wpływu na możliwość wystąpienia poślizgu.", "C": "Zwiększa możliwość wystąpienia poślizgu."}'::jsonb, 'C'),
('PT', 'specjalistyczne'::question_type, 3, 'Jaki wpływ na zachowanie tramwaju ma obecność liści na torowisku?', '{"A": "Nie ma wpływu na przyczepność.", "B": "Zmniejsza przyczepność.", "C": "Zwiększa przyczepność."}'::jsonb, 'B'),
('PT', 'specjalistyczne'::question_type, 3, 'Jaki wpływ na stan torowiska ma początkowa faza opadów?', '{"A": "Powoduje poprawienie przyczepności między kołami a szynami.", "B": "Stwarza zagrożenie poślizgu podczas rozruchu i hamowania.", "C": "Nie ma żadnego wpływu na jazdę tramwajem."}'::jsonb, 'B'),
('PT', 'specjalistyczne'::question_type, 3, 'Kiedy opady deszczu mają największy wpływ na rozruch i hamowanie tramwaju?', '{"A": "W początkowej fazie.", "B": "Kiedy długotrwały deszcz przechodzi w stan mżawki.", "C": "W końcowej fazie."}'::jsonb, 'A'),
('PT', 'specjalistyczne'::question_type, 3, 'Co zwiększa ryzyko wystąpienia poślizgu tramwaju?', '{"A": "Nagrzanie szyn przez słońce.", "B": "Oddziaływanie piasku i kurzu pokrywających szyny.", "C": "Zaleganie mokrych liści na torowisku."}'::jsonb, 'C'),
('PT', 'specjalistyczne'::question_type, 3, 'W której porze roku warunki do jazdy tramwajem są najtrudniejsze?', '{"A": "Wiosną.", "B": "Zimą.", "C": "Jesienią."}'::jsonb, 'C'),
('PT', 'specjalistyczne'::question_type, 3, 'Jak powienien zachować się motorniczy, jeżeli główki szyn są zalane wodą na znaczynym odcinku?', '{"A": "Zatrzymać tramwaj.", "B": "Przejechać z małą prędkością.", "C": "Przejechać z dużą prędkością."}'::jsonb, 'A'),
