('PT', 'specjalistyczne'::question_type, 1, 'W jakiej sytuacji, podczas jazdy, motorniczemu wolno wyłączyć blokadę jazdy?', '{"A": "Na żądanie pasażera.", "B": "Przy dużym napełnieniu wagonu.", "C": "W każdej sytuacji jest zabronione."}'::jsonb, 'C'),
('PT', 'specjalistyczne'::question_type, 2, 'W który z wymienionych systemów hamowania powinien być wyposażony każdy tramwaj liniowy?', '{"A": "Sieciowy.", "B": "Roboczy.", "C": "Ręczny."}'::jsonb, 'B'),
('PT', 'specjalistyczne'::question_type, 1, 'Co należy sprawdzić w pierwszej kolejności jeśli po załączeniu jazdy tramwaj nie rusza?', '{"A": "Napięcie przetwornicy.", "B": "Ustawienie nawrotnika kierunku.", "C": "Sygnalizację zamknięcia drzwi."}'::jsonb, 'C'),
('PT', 'specjalistyczne'::question_type, 1, 'Jakie napięcie powienien wskazywać woltomierz po włączeniu baterii?', '{"A": "Nie mniejsze niż 38 V.", "B": "Mniejsze niż wartość określona dla danego typu tramwaju.", "C": "Większe niż wartość określona dla danego typu tramwaju."}'::jsonb, 'C'),
('PT', 'specjalistyczne'::question_type, 1, 'Co powienien zrobić motorniczy, jeśli po załączeniu jazdy nie nastąpi odhamowanie hamulców szczękowych?', '{"A": "Kontynuować jazdę bez podejmowania żadnych działań.", "B": "Odpiąć luzowniki.", "C": "Wezwać nadzór ruchu, bo nie jest to możliwe bez specjalistycznych narzędzi."}'::jsonb, 'B'),
('PT', 'specjalistyczne'::question_type, 1, 'Jaki skutek wywołuje wciśnięcie pedału lub wychylenie dźwigni hamulca elektordynamicznego "za ogranicznik"?', '{"A": "Włączenie się hamulców szynowych.", "B": "Zwiększenie efektywności działania hamulców elektrodynamicznych.", "C": "Uszkodzenie układu hamulcowego."}'::jsonb, 'A'),
('PT', 'specjalistyczne'::question_type, 1, 'Czym najczęściej spowodowany jest zanik rozruchu?', '{"A": "Brakiem zasilania tramwaju (np. zanik w sieci lub zatrzymanie tramwaju \"na izolatorze\").", "B": "Uszkodzeniem oświetlenia wewnętrznego wagonu.", "C": "Czynnikami atmosferycznymi."}'::jsonb, 'A'),
('B', 'specjalistyczne'::question_type, 3, 'Która z tych czynności zwiększy bezpieczeństwo jazdy, gdy kierujesz samochodem osobowym podczas mgły ograniczającej widoczność do 40 metrów?', '{"A": "Włączenie świateł drogowych.", "B": "Zmniejszenie odstępu od poprzedzającego pojazdu.", "C": "Włączenie świateł przeciwmgłowych tylnych."}'::jsonb, 'C'),
