('PT', 'specjalistyczne'::question_type, 3, 'Jak motorniczy powinien ustawić  prawe zewnętrzne lusterko?', '{"A": "Aby widać było cały peron i pasażerów.", "B": "Aby był widoczny bok tramwaju oraz przestrzeń za pojazdem.", "C": "Może je złożyć, ponieważ podczas jazdy nie jest przydatne."}'::jsonb, 'B'),
('PT', 'specjalistyczne'::question_type, 3, 'Z jaką dopuszczalną prędkością możesz jechać w strefie zamieszkania?', '{"A": "40 km/h", "B": "30 km/h", "C": "20 km/h"}'::jsonb, 'C'),
