('B1', 'specjalistyczne'::question_type, 3, 'Jakie jest ryzyko poślizgu pojazdu podczas jazdy w czasie deszczu?', '{"A": "Największe w początkowej fazie deszczu.", "B": "Najmniejsze w początkowej fazie deszczu.", "C": "Największe w końcowej fazie deszczu."}'::jsonb, 'A'),
('B', 'specjalistyczne'::question_type, 2, 'Jaki wpływ ma prędkość jazdy na kąt widzenia kierującego samochodem osobowym?', '{"A": "Wraz ze wzrostem prędkości kąt widzenia zawęża się.", "B": "Wraz ze wzrostem prędkości kąt widzenia rozszerza się.", "C": "Nie ma żadnego wpływu."}'::jsonb, 'A'),
